import json, sys

def extract(path, out):
    lines_out = []
    with open(path, 'r', encoding='utf-8') as f:
        for raw in f:
            raw = raw.strip()
            if not raw:
                continue
            try:
                obj = json.loads(raw)
            except Exception:
                continue
            t = obj.get('type')
            if t not in ('user', 'assistant'):
                continue
            msg = obj.get('message', {})
            role = msg.get('role', t)
            content = msg.get('content')
            parts = []
            if isinstance(content, str):
                parts.append(content)
            elif isinstance(content, list):
                for b in content:
                    if not isinstance(b, dict):
                        continue
                    bt = b.get('type')
                    if bt == 'text':
                        parts.append(b.get('text', ''))
                    elif bt == 'thinking':
                        # skip thinking to save space, or include truncated
                        continue
                    elif bt == 'tool_use':
                        name = b.get('name', '?')
                        inp = b.get('input', {})
                        # summarize tool input compactly
                        desc = inp.get('description') or inp.get('command') or inp.get('file_path') or inp.get('prompt') or inp.get('pattern') or ''
                        if isinstance(desc, str):
                            desc = desc.replace('\n', ' ')[:200]
                        parts.append(f"[TOOL:{name}] {desc}")
                    elif bt == 'tool_result':
                        # skip large tool results
                        continue
            text = '\n'.join(p for p in parts if p and p.strip())
            if not text.strip():
                continue
            # skip pure tool-call-only assistant turns that have no text? keep them lightly
            lines_out.append(f"\n===== {role.upper()} =====\n{text}")
    with open(out, 'w', encoding='utf-8') as f:
        f.write('\n'.join(lines_out))
    # report size
    import os
    print(out, os.path.getsize(out), 'bytes,', len(lines_out), 'blocks')

extract(sys.argv[1], sys.argv[2])

