import csv,glob,os,re
BASE="C:/Users/terry/Downloads"; RPT=f"{BASE}/搜索查询绩效报告2026.07.09"
def ym(fn):
    m=re.search(r"(\d{4})_(\d{2})_\d{2}\.csv$", fn)
    return f"{m.group(1)}-{m.group(2)}" if m else "?"
def rowcount(fn):
    try:
        for e in ("utf-8-sig","gbk","utf-8"):
            try:
                n=sum(1 for _ in open(fn,encoding=e)); return n-2  # minus 2 header rows
            except: pass
    except: return "?"
def audit(folder,label,pat="*.csv"):
    files=sorted(glob.glob(f"{folder}/{pat}"), key=ym)
    months=[ym(f) for f in files]
    counts={ym(f):rowcount(f) for f in files}
    print(f"\n## {label}")
    print(f"   月份数={len(months)}  范围: {months[0]} ~ {months[-1]}" if months else "   （空）")
    print(f"   全部月份: {', '.join(months)}")
    # gap detection
    def idx(m): y,mm=m.split('-'); return int(y)*12+int(mm)
    gaps=[]
    for i in range(1,len(months)):
        if idx(months[i])-idx(months[i-1])>1: gaps.append(f"{months[i-1]}→{months[i]}")
    print(f"   缺口: {gaps if gaps else '无'}")
    thin=[m for m,c in counts.items() if isinstance(c,int) and c<20]
    print(f"   数据行<20的薄月: {thin if thin else '无'}  (行数样例: "+", ".join(f'{m}:{counts[m]}' for m in months[:3])+" ...)")

