    elif posdiv>=5 and vol>=150 and (hprice or 0)>=180: v="加投主攻·正背离"
    else: v="次选/机会池"
    gate="毛利可撑" if horse in("X1","S1","S3") else ("薄利·冲量看7%线" if horse in("S2","X2") else "—")
    rows.append(dict(w=w,v=v,vol=int(vol),opp=int(opp),oursh=round(oursh,1),units=int(ourunits),mon=a["mon"],
        SoV=round(SoV,1),SoC=round(SoC,1),SoP=round(SoP,1),leak=leak,conc=round(conc,1),
