        margin=margin.get(horse,""),oper=op.get(horse,"—"),gate=gate))
rows.sort(key=lambda r:r["opp"],reverse=True)

cols=["v","w","opp","vol","oursh","units","mon","SoV","SoC","SoP","leak","conc","comp","compbrand","trend","horse","hprice","clickmed","margin","oper","gate"]
h={"v":"判定","w":"搜索词","opp":"12月机会单","vol":"12月大盘成交","oursh":"我成交份额%","units":"我12月成交","mon":"覆盖月数","SoV":"曝光份额%","SoC":"点击份额%","SoP":"成交份额%","leak":"最大漏点","conc":"竞品前3集中度%","comp":"头号竞品ASIN","compbrand":"竞品品牌(约)","trend":"竞品趋势","horse":"应战型号","hprice":"该ASIN成交价$","clickmed":"大盘点击中位$","margin":"该ASIN毛利%","oper":"运营","gate":"毛利闸"}
